export async function POST(req) {
  const auth = requireAdmin(req); if (auth) return auth;
  
  for (const w of WILAYAS_AR) {
    await prisma.wilaya.updateMany({ where: { id: w.id }, data: { name_ar: w.name_ar } });
  }
  
  for (const [wilayaId, communes] of Object.entries(COMMUNES_BY_WILAYA)) {
    const cases = communes.map(c => 
      `WHEN name = '${c['name'].replace(/'/g, "''")}' THEN '${c['name_ar'].replace(/'/g, "''")}'`
    ).join('\n');
    await prisma.$executeRawUnsafe(`
      UPDATE "Commune" SET name_ar = CASE ${cases} END
      WHERE "wilayaId" = ${parseInt(wilayaId)} AND name IN (${communes.map(c => `'${c['name'].replace(/'/g, "''")}'`).join(',')})
    `);
  }
  
  return Response.json({ ok: true, wilayas: WILAYAS_AR.length });
}
